section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "testing-go-output",
  "required": [
    "test_files",
    "test_function_count",
    "table_driven_count",
    "forbidden_seen",
    "require_used"
  ],
  "properties": {
    "test_files": {
      "description": "Paths of Go test files produced."
    },
    "test_function_count": {
      "description": "Total `Test*` functions across files."
    },
    "table_driven_count": {
      "description": "Tests using a table + `t.Run`."
    },
    "benchmark_count": {
      "description": "`Benchmark*` functions present."
    },
    "fuzz_targets": {
      "description": "Names of `Fuzz*` functions."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    },
    "require_used": {
      "description": "`require` used for nil/error preconditions."
    }
  }
}
